#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WorkExternalUserIdMigrationResponse {
    #[serde(default)]
    pub errcode: Option<i64>,
    #[serde(default)]
    pub errmsg: Option<String>,
    #[serde(default)]
    pub items: Vec<WorkExternalUserIdMigrationItem>,
    #[serde(default, flatten, skip_serializing_if = "Value::is_null")]
    pub extra: Value,
}

impl WorkExternalUserIdMigrationResponse {
    pub fn validate(&self) -> Result<()> {
        validate_work_response_success(
            "external-contact userid migration",
            self.errcode,
            self.errmsg.as_deref(),
        )?;
        if self.items.len() > 1_000 {
            return Err(WechatError::Config(
                "external-contact userid migration cannot exceed 1000 mappings".to_string(),
            ));
        }
        let mut source_ids = std::collections::HashSet::with_capacity(self.items.len());
        for item in &self.items {
            item.validate()?;
            let source_id = item.external_userid.as_deref().unwrap_or_default();
            if !source_ids.insert(source_id) {
                return Err(WechatError::Config(
                    "external-contact userid migration cannot contain duplicate source ids"
                        .to_string(),
                ));
            }
        }
        Ok(())
    }

    pub fn mapped_count(&self) -> usize {
        self.items.iter().filter(|item| item.is_mapped()).count()
    }

    pub fn changed_count(&self) -> usize {
        self.items.iter().filter(|item| item.is_changed()).count()
    }

    pub fn find_mapping(&self, external_userid: &str) -> Option<&WorkExternalUserIdMigrationItem> {
        self.items.iter().find(|item| {
            item.external_userid
                .as_deref()
                .is_some_and(|value| value == external_userid)
        })
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WorkExternalUserIdMigrationItem {
    #[serde(default)]
    pub external_userid: Option<String>,
    #[serde(default)]
    pub new_external_userid: Option<String>,
    #[serde(default, flatten, skip_serializing_if = "Value::is_null")]
    pub extra: Value,
}

impl WorkExternalUserIdMigrationItem {
    pub fn validate(&self) -> Result<()> {
        let source = self.external_userid.as_deref().ok_or_else(|| {
            WechatError::Config(
                "external-contact userid migration item requires external_userid".to_string(),
            )
        })?;
        let target = self.new_external_userid.as_deref().ok_or_else(|| {
            WechatError::Config(
                "external-contact userid migration item requires new_external_userid".to_string(),
            )
        })?;
        validate_external_contact_identifier("external userid", source)?;
        validate_external_contact_identifier("new external userid", target)
    }

    pub fn is_mapped(&self) -> bool {
        self.external_userid
            .as_deref()
            .is_some_and(|external_userid| !external_userid.trim().is_empty())
            && self
                .new_external_userid
                .as_deref()
                .is_some_and(|external_userid| !external_userid.trim().is_empty())
    }

    pub fn is_changed(&self) -> bool {
        self.is_mapped() && self.external_userid != self.new_external_userid
    }
}

fn validate_external_user_id_migration_list(external_userids: &[String]) -> Result<()> {
    if external_userids.is_empty() || external_userids.len() > 1_000 {
        return Err(WechatError::Config(
            "external-userid migration must contain between 1 and 1000 ids".to_string(),
        ));
    }
    if external_userids
        .iter()
        .any(|external_userid| external_userid.trim().is_empty())
        || has_duplicate_strings(external_userids)
    {
        return Err(WechatError::Config(
            "external-userid migration ids must be non-empty and unique".to_string(),
        ));
    }
    Ok(())
}

