#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WorkTemplateCardUpdateRequest {
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub userids: Vec<String>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub partyids: Vec<String>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub tagids: Vec<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub atall: Option<i64>,
    pub agentid: i64,
    pub response_code: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub button: Option<WorkTemplateCardUpdateButton>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub template_card: Option<WorkTemplateCard>,
    #[serde(default, flatten, skip_serializing_if = "Value::is_null")]
    pub extra: Value,
}

impl WorkTemplateCardUpdateRequest {
    pub fn template_card_type_kind(&self) -> Option<WorkTemplateCardTypeKind> {
        self.template_card
            .as_ref()
            .map(WorkTemplateCard::card_type_kind)
    }

    pub fn validate(&self) -> Result<()> {
        if self.agentid <= 0 {
            return Err(WechatError::Config(
                "work template-card update agent id must be positive".to_string(),
            ));
        }
        validate_work_message_identifier("template-card response code", &self.response_code)?;
        for (label, identifiers) in [
            ("user ids", &self.userids),
            ("department ids", &self.partyids),
            ("tag ids", &self.tagids),
        ] {
            if identifiers
                .iter()
                .any(|identifier| identifier.trim().is_empty())
                || has_duplicate_strings(identifiers)
            {
                return Err(WechatError::Config(format!(
                    "work template-card update {label} must be non-empty and unique"
                )));
            }
        }
        if self.userids.len() > 1000 || self.partyids.len() > 100 || self.tagids.len() > 100 {
            return Err(WechatError::Config(
                "work template-card updates support at most 1000 users, 100 departments, and 100 tags"
                    .to_string(),
            ));
        }
        if self.atall.is_some_and(|atall| !matches!(atall, 0 | 1)) {
            return Err(WechatError::Config(
                "work template-card update atall must be 0 or 1".to_string(),
            ));
        }
        if self.userids.is_empty()
            && self.partyids.is_empty()
            && self.tagids.is_empty()
            && self.atall != Some(1)
        {
            return Err(WechatError::Config(
                "work template-card updates require recipients or atall=1".to_string(),
            ));
        }
        if self.button.is_none() && self.template_card.is_none() {
            return Err(WechatError::Config(
                "work template-card updates require a button or template-card payload".to_string(),
            ));
        }
        if self
            .button
            .as_ref()
            .is_some_and(|button| button.replace_name.trim().is_empty())
        {
            return Err(WechatError::Config(
                "work template-card replacement button name cannot be empty".to_string(),
            ));
        }
        if let Some(template_card) = &self.template_card {
            let payload = to_value(template_card).map_err(|error| {
                WechatError::Config(format!(
                    "work template-card update payload cannot be serialized: {error}"
                ))
            })?;
            validate_work_message_payload(WorkMessageTypeKind::TemplateCard.as_code(), &payload)?;
        }
        Ok(())
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WorkTemplateCardUpdateButton {
    pub replace_name: String,
    #[serde(default, flatten, skip_serializing_if = "Value::is_null")]
    pub extra: Value,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum WorkTemplateCardTypeKind {
    TextNotice,
    NewsNotice,
    ButtonInteraction,
    VoteInteraction,
    MultipleInteraction,
    Other,
}

impl WorkTemplateCardTypeKind {
    pub fn from_code(value: &str) -> Self {
        if value.eq_ignore_ascii_case("text_notice") {
            Self::TextNotice
        } else if value.eq_ignore_ascii_case("news_notice") {
            Self::NewsNotice
        } else if value.eq_ignore_ascii_case("button_interaction") {
            Self::ButtonInteraction
        } else if value.eq_ignore_ascii_case("vote_interaction") {
            Self::VoteInteraction
        } else if value.eq_ignore_ascii_case("multiple_interaction") {
            Self::MultipleInteraction
        } else {
            Self::Other
        }
    }

    pub fn as_code(self) -> &'static str {
        match self {
            Self::TextNotice => "text_notice",
            Self::NewsNotice => "news_notice",
            Self::ButtonInteraction => "button_interaction",
            Self::VoteInteraction => "vote_interaction",
            Self::MultipleInteraction => "multiple_interaction",
            Self::Other => "unknown",
        }
    }

    pub fn is_interactive(self) -> bool {
        matches!(
            self,
            Self::ButtonInteraction | Self::VoteInteraction | Self::MultipleInteraction
        )
    }
}

