#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WorkUserRequest {
    pub userid: String,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub name: Option<String>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub department: Vec<i64>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub order: Vec<i64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub position: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub mobile: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub gender: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub email: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub biz_mail: Option<String>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub is_leader_in_dept: Vec<i64>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub direct_leader: Vec<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub telephone: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub alias: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub address: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub main_department: Option<i64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub to_invite: Option<bool>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub enable: Option<i64>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub avatar_mediaid: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub external_position: Option<String>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub external_profile: Option<WorkUserExternalProfile>,
    #[serde(skip_serializing_if = "Option::is_none")]
    pub extattr: Option<WorkUserExtAttr>,
}

impl WorkUserRequest {
    pub fn validate_for_create(&self) -> Result<()> {
        self.validate_common()?;
        if self
            .name
            .as_deref()
            .is_none_or(|name| name.trim().is_empty())
            || self.department.is_empty()
        {
            return Err(WechatError::Config(
                "work user creation requires a non-empty name and at least one department"
                    .to_string(),
            ));
        }
        Ok(())
    }

    pub fn validate_for_update(&self) -> Result<()> {
        self.validate_common()?;
        let has_patch = self.name.is_some()
            || !self.department.is_empty()
            || !self.order.is_empty()
            || self.position.is_some()
            || self.mobile.is_some()
            || self.gender.is_some()
            || self.email.is_some()
            || self.biz_mail.is_some()
            || !self.is_leader_in_dept.is_empty()
            || !self.direct_leader.is_empty()
            || self.telephone.is_some()
            || self.alias.is_some()
            || self.address.is_some()
            || self.main_department.is_some()
            || self.to_invite.is_some()
            || self.enable.is_some()
            || self.avatar_mediaid.is_some()
            || self.external_position.is_some()
            || self.external_profile.is_some()
            || self.extattr.is_some();
        if !has_patch {
            return Err(WechatError::Config(
                "work user updates require at least one changed field".to_string(),
            ));
        }
        Ok(())
    }

    fn validate_common(&self) -> Result<()> {
        validate_work_user_identifier("user id", &self.userid)?;
        if self.userid.chars().count() > 64 {
            return Err(WechatError::Config(
                "work user id cannot exceed 64 characters".to_string(),
            ));
        }
        if self
            .name
            .as_ref()
            .is_some_and(|name| name.chars().count() > 64)
        {
            return Err(WechatError::Config(
                "work user name cannot exceed 64 characters".to_string(),
            ));
        }
        if self.department.len() > 20
            || self.department.iter().any(|department| *department <= 0)
            || has_duplicate_i64(&self.department)
        {
            return Err(WechatError::Config(
                "work users support at most 20 unique positive departments".to_string(),
            ));
        }
        for (label, values) in [
            ("department order", &self.order),
            ("department leader flags", &self.is_leader_in_dept),
        ] {
            if !values.is_empty() && values.len() != self.department.len() {
                return Err(WechatError::Config(format!(
                    "work user {label} must align with the department list"
                )));
            }
        }
        if self
            .is_leader_in_dept
            .iter()
            .any(|flag| !matches!(flag, 0 | 1))
        {
            return Err(WechatError::Config(
                "work user department leader flags must be 0 or 1".to_string(),
            ));
        }
        if self
            .main_department
            .is_some_and(|main| !self.department.is_empty() && !self.department.contains(&main))
        {
            return Err(WechatError::Config(
                "work user main department must appear in the department list".to_string(),
            ));
        }
        if self
            .gender
            .as_deref()
            .is_some_and(|gender| !matches!(gender, "1" | "2"))
        {
            return Err(WechatError::Config(
                "work user gender must be 1 or 2".to_string(),
            ));
        }
        if self.enable.is_some_and(|enable| !matches!(enable, 0 | 1)) {
            return Err(WechatError::Config(
                "work user enable must be 0 or 1".to_string(),
            ));
        }
        Ok(())
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WorkUserBatchDeleteRequest {
    pub useridlist: Vec<String>,
}

impl WorkUserBatchDeleteRequest {
    pub fn new(userids: impl IntoIterator<Item = impl Into<String>>) -> Self {
        Self {
            useridlist: userids.into_iter().map(Into::into).collect(),
        }
    }

    pub fn validate(&self) -> Result<()> {
        validate_work_user_string_batch("batch deletion", &self.useridlist, 200)
    }
}

fn validate_work_user_identifier(label: &str, value: &str) -> Result<()> {
    if value.trim().is_empty() {
        return Err(WechatError::Config(format!(
            "work user {label} cannot be empty"
        )));
    }
    Ok(())
}

fn validate_work_user_id(user_id: &str) -> Result<()> {
    validate_work_user_identifier("id", user_id)?;
    if user_id.chars().count() > 64 {
        return Err(WechatError::Config(
            "work user id cannot exceed 64 characters".to_string(),
        ));
    }
    Ok(())
}

fn validate_work_department_id(department_id: i64) -> Result<()> {
    if department_id <= 0 {
        return Err(WechatError::Config(
            "work department id must be positive".to_string(),
        ));
    }
    Ok(())
}

fn validate_work_mobile(mobile: &str) -> Result<()> {
    let trimmed = mobile.trim();
    let digits = trimmed.strip_prefix('+').unwrap_or(trimmed);
    if !(5..=32).contains(&digits.len()) || !digits.bytes().all(|byte| byte.is_ascii_digit()) {
        return Err(WechatError::Config(
            "work user mobile must contain 5 to 32 digits with an optional leading +".to_string(),
        ));
    }
    Ok(())
}

fn validate_work_email(email: &str) -> Result<()> {
    let trimmed = email.trim();
    let Some((local, domain)) = trimmed.split_once('@') else {
        return Err(WechatError::Config(
            "work user email must be a valid email address".to_string(),
        ));
    };
    if trimmed.len() > 254
        || local.is_empty()
        || local.len() > 64
        || domain.is_empty()
        || !domain.contains('.')
        || domain.starts_with('.')
        || domain.ends_with('.')
        || trimmed.chars().any(char::is_whitespace)
        || domain.split('.').any(str::is_empty)
    {
        return Err(WechatError::Config(
            "work user email must be a valid email address".to_string(),
        ));
    }
    Ok(())
}

fn validate_work_active_stat_date(date: &str) -> Result<()> {
    let parsed = chrono::NaiveDate::parse_from_str(date, "%Y-%m-%d").map_err(|_| {
        WechatError::Config("work active-stat date must use YYYY-MM-DD".to_string())
    })?;
    let today = chrono::Utc::now().date_naive();
    let age = today.signed_duration_since(parsed).num_days();
    if !(0..=30).contains(&age) {
        return Err(WechatError::Config(
            "work active-stat date must be today or within the previous 30 days".to_string(),
        ));
    }
    Ok(())
}

fn validate_work_tag_id(tag_id: i64) -> Result<()> {
    if tag_id <= 0 {
        return Err(WechatError::Config(
            "work tag id must be positive".to_string(),
        ));
    }
    Ok(())
}

fn parse_work_tag_id(tag_id: String) -> Result<i64> {
    let parsed = tag_id
        .trim()
        .parse::<i64>()
        .map_err(|_| WechatError::Config("work tag id must be a positive integer".to_string()))?;
    validate_work_tag_id(parsed)?;
    Ok(parsed)
}

fn validate_work_tag_name(tag_name: &str) -> Result<()> {
    let length = tag_name.chars().count();
    if tag_name.trim().is_empty() || length > 32 {
        return Err(WechatError::Config(
            "work tag name must contain between 1 and 32 characters".to_string(),
        ));
    }
    Ok(())
}

fn validate_work_tag_members(user_ids: &[String], party_ids: &[String]) -> Result<Vec<i64>> {
    if user_ids.is_empty() && party_ids.is_empty() {
        return Err(WechatError::Config(
            "work tag membership change requires at least one user or department".to_string(),
        ));
    }
    if user_ids.len() + party_ids.len() > 1_000 {
        return Err(WechatError::Config(
            "work tag membership change cannot exceed 1000 users and departments".to_string(),
        ));
    }
    if !user_ids.is_empty() {
        validate_work_user_string_batch("tag membership", user_ids, 1_000)?;
        if user_ids.iter().any(|user_id| user_id.chars().count() > 64) {
            return Err(WechatError::Config(
                "work tag member user id cannot exceed 64 characters".to_string(),
            ));
        }
    }
    let parsed = party_ids
        .iter()
        .map(|party_id| {
            party_id.trim().parse::<i64>().map_err(|_| {
                WechatError::Config("work tag department ids must be positive integers".to_string())
            })
        })
        .collect::<Result<Vec<_>>>()?;
    if parsed.iter().any(|party_id| *party_id <= 0) || has_duplicate_i64(&parsed) {
        return Err(WechatError::Config(
            "work tag department ids must be unique positive integers".to_string(),
        ));
    }
    Ok(parsed)
}

fn validate_work_user_job_id(job_id: &str) -> Result<()> {
    validate_work_user_identifier("job id", job_id)?;
    if job_id.chars().count() > 64 {
        return Err(WechatError::Config(
            "work user job id cannot exceed 64 characters".to_string(),
        ));
    }
    Ok(())
}

fn validate_work_user_string_batch(label: &str, values: &[String], maximum: usize) -> Result<()> {
    if values.is_empty()
        || values.len() > maximum
        || values.iter().any(|value| value.trim().is_empty())
        || has_duplicate_strings(values)
    {
        return Err(WechatError::Config(format!(
            "work user {label} requires 1 to {maximum} unique non-empty identifiers"
        )));
    }
    Ok(())
}

fn work_user_response_identity<'a>(
    userid: Option<&'a str>,
    open_userid: Option<&'a str>,
) -> Option<&'a str> {
    userid
        .filter(|value| !value.trim().is_empty())
        .or_else(|| open_userid.filter(|value| !value.trim().is_empty()))
}

fn validate_work_user_response_identity(
    label: &str,
    userid: Option<&str>,
    open_userid: Option<&str>,
) -> Result<()> {
    for (kind, value) in [("userid", userid), ("open_userid", open_userid)] {
        if value.is_some_and(|value| value.trim().is_empty()) {
            return Err(WechatError::Config(format!(
                "work user {label} response {kind} cannot be blank"
            )));
        }
    }
    if work_user_response_identity(userid, open_userid).is_none() {
        return Err(WechatError::Config(format!(
            "work user {label} response requires userid or open_userid"
        )));
    }
    Ok(())
}

fn validate_work_user_response_departments(departments: &[i64]) -> Result<()> {
    if departments.len() > 20
        || departments.iter().any(|department| *department <= 0)
        || has_duplicate_i64(departments)
    {
        return Err(WechatError::Config(
            "work user response departments must contain at most 20 unique positive ids"
                .to_string(),
        ));
    }
    Ok(())
}

fn validate_work_user_unique_response_identities<'a>(
    label: &str,
    identities: impl Iterator<Item = &'a str>,
) -> Result<()> {
    let mut seen = std::collections::HashSet::new();
    if identities
        .into_iter()
        .any(|identity| !seen.insert(identity))
    {
        return Err(WechatError::Config(format!(
            "work user {label} response cannot contain duplicate identities"
        )));
    }
    Ok(())
}

fn validate_work_linked_corp_identifiers(label: &str, values: &[String]) -> Result<()> {
    if values.iter().any(|value| value.trim().is_empty()) || has_duplicate_strings(values) {
        return Err(WechatError::Config(format!(
            "work linked-corp {label} ids must be unique and non-empty"
        )));
    }
    Ok(())
}

fn validate_work_user_http_url(label: &str, value: &str) -> Result<()> {
    let parsed = url::Url::parse(value).map_err(|error| {
        WechatError::Config(format!("work user {label} URL is invalid: {error}"))
    })?;
    if !matches!(parsed.scheme(), "http" | "https") || parsed.host_str().is_none() {
        return Err(WechatError::Config(format!(
            "work user {label} must be an absolute HTTP(S) URL"
        )));
    }
    Ok(())
}

fn has_duplicate_i64(values: &[i64]) -> bool {
    let mut seen = std::collections::HashSet::new();
    values.iter().any(|value| !seen.insert(*value))
}

