#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ExternalContactServedListRequest {
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub cursor: Option<String>,
    #[serde(default, skip_serializing_if = "Option::is_none")]
    pub limit: Option<i64>,
}

impl ExternalContactServedListRequest {
    pub fn first_page(limit: i64) -> Self {
        Self {
            cursor: None,
            limit: Some(limit),
        }
    }

    pub fn next_page(cursor: impl Into<String>, limit: i64) -> Self {
        Self {
            cursor: Some(cursor.into()),
            limit: Some(limit),
        }
    }

    pub fn validate(&self) -> Result<()> {
        validate_external_contact_page(self.cursor.as_deref(), self.limit, 1000)
    }
}

fn validate_external_contact_page(
    cursor: Option<&str>,
    limit: Option<i64>,
    maximum_limit: i64,
) -> Result<()> {
    if cursor.is_some_and(|cursor| cursor.trim().is_empty()) {
        return Err(WechatError::Config(
            "external-contact pagination cursor cannot be empty".to_string(),
        ));
    }
    if limit.is_some_and(|limit| !(1..=maximum_limit).contains(&limit)) {
        return Err(WechatError::Config(format!(
            "external-contact page limit must be between 1 and {maximum_limit}"
        )));
    }
    Ok(())
}

fn validate_external_contact_identifier(label: &str, value: &str) -> Result<()> {
    if value.trim().is_empty() {
        return Err(WechatError::Config(format!(
            "external-contact {label} cannot be empty"
        )));
    }
    Ok(())
}

fn validate_external_contact_response_ids(
    label: &str,
    values: &[String],
    require_values: bool,
) -> Result<()> {
    if require_values && values.is_empty() {
        return Err(WechatError::Config(format!(
            "external-contact {label} list cannot be empty"
        )));
    }
    let mut unique = std::collections::HashSet::with_capacity(values.len());
    for value in values {
        validate_external_contact_identifier(label, value)?;
        if !unique.insert(value.as_str()) {
            return Err(WechatError::Config(format!(
                "external-contact {label} list cannot contain duplicates"
            )));
        }
    }
    Ok(())
}

