        self.effective_range()
            .ok_or_else(|| {
                WechatError::Config(
                    "customer-acquisition link get response requires range".to_string(),
                )
            })?
            .validate()?;
        if let Some(priority_option) = self.effective_priority_option() {
            priority_option.validate()?;
        }
        Ok(())
