#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ExternalContactProductAlbum {
    #[serde(default)]
    pub product_id: Option<String>,
    #[serde(default)]
    pub product_sn: Option<String>,
    #[serde(default)]
    pub description: Option<String>,
    #[serde(default)]
    pub price: Option<i64>,
    #[serde(default)]
    pub create_time: Option<i64>,
    #[serde(default)]
    pub attachments: Vec<ExternalContactProductAttachment>,
    #[serde(default, flatten, skip_serializing_if = "Value::is_null")]
    pub extra: Value,
}

impl ExternalContactProductAlbum {
    pub fn validate(&self) -> Result<()> {
        validate_external_contact_product_id(self.product_id.as_deref().ok_or_else(|| {
            WechatError::Config(
                "external-contact product-album response requires product_id".to_string(),
            )
        })?)?;
        if let Some(product_sn) = self.product_sn.as_deref() {
            validate_external_contact_product_sn(product_sn, true)?;
        }
        validate_external_contact_product_description(self.description.as_deref().ok_or_else(
            || {
                WechatError::Config(
                    "external-contact product-album response requires description".to_string(),
                )
            },
        )?)?;
        validate_external_contact_product_price(self.price.ok_or_else(|| {
            WechatError::Config(
                "external-contact product-album response requires price".to_string(),
            )
        })?)?;
        if !(1..=9).contains(&self.attachments.len()) {
            return Err(WechatError::Config(
                "external-contact product-album response requires 1 to 9 attachments".to_string(),
            ));
        }
        for attachment in &self.attachments {
            attachment.validate_response()?;
        }
        let image_media_ids = self
            .attachments
            .iter()
            .filter_map(|attachment| attachment.image.as_ref())
            .map(|image| image.media_id.as_str())
            .collect::<Vec<_>>();
        if has_duplicate_strings(&image_media_ids) {
            return Err(WechatError::Config(
                "external-contact product response image media ids must be unique".to_string(),
            ));
        }
        if self.create_time.is_some_and(|create_time| create_time <= 0) {
            return Err(WechatError::Config(
                "external-contact product create_time must be positive".to_string(),
            ));
        }
        Ok(())
    }

    pub fn has_identity(&self) -> bool {
        self.product_id
            .as_deref()
            .is_some_and(|product_id| !product_id.trim().is_empty())
    }

    pub fn image_count(&self) -> usize {
        self.attachments
            .iter()
            .filter(|attachment| {
                matches!(
                    attachment.kind(),
                    ExternalContactProductAttachmentKind::Image
                )
            })
            .count()
    }

    pub fn price_parts(&self) -> Option<(i64, u8)> {
        let price = self.price?;
        (price >= 0).then_some((price / 100, (price % 100) as u8))
    }

    pub fn formatted_price(&self) -> Option<String> {
        let (yuan, cents) = self.price_parts()?;
        Some(format!("{yuan}.{cents:02}"))
    }
}

fn validate_external_contact_product_id(product_id: &str) -> Result<()> {
    validate_external_contact_identifier("product id", product_id)?;
    if product_id.len() > 128 {
        return Err(WechatError::Config(
            "external-contact product id cannot exceed 128 UTF-8 bytes".to_string(),
        ));
    }
    Ok(())
}

fn validate_external_contact_product_description(description: &str) -> Result<()> {
    let character_count = description.chars().count();
    if description.trim().is_empty() || character_count > 300 {
        return Err(WechatError::Config(
            "external-contact product description must contain 1 to 300 characters".to_string(),
        ));
    }
    Ok(())
}

fn validate_external_contact_product_price(price: i64) -> Result<()> {
    if !(0..=5_000_000).contains(&price) {
        return Err(WechatError::Config(
            "external-contact product price must be between 0 and 5000000 cents".to_string(),
        ));
    }
    Ok(())
}

fn validate_external_contact_product_sn(product_sn: &str, allow_empty: bool) -> Result<()> {
    if product_sn.is_empty() && allow_empty {
        return Ok(());
    }
    if product_sn.is_empty()
        || product_sn.len() > 128
        || !product_sn.bytes().all(|byte| byte.is_ascii_alphanumeric())
    {
        return Err(WechatError::Config(
            "external-contact product code must contain 1 to 128 ASCII letters or digits"
                .to_string(),
        ));
    }
    Ok(())
}

fn validate_external_contact_product_attachments(
    attachments: &[ExternalContactProductAttachment],
) -> Result<()> {
    if !(1..=9).contains(&attachments.len()) {
        return Err(WechatError::Config(
            "external-contact product requires 1 to 9 image attachments".to_string(),
        ));
    }
    for attachment in attachments {
        attachment.validate()?;
    }
    let media_ids = attachments
        .iter()
        .filter_map(|attachment| attachment.image.as_ref())
        .map(|image| image.media_id.as_str())
        .collect::<Vec<_>>();
    if has_duplicate_strings(&media_ids) {
        return Err(WechatError::Config(
            "external-contact product image media ids must be unique".to_string(),
        ));
    }
    Ok(())
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CustomerAcquisitionQuotaResponse {
    #[serde(default)]
    pub errcode: Option<i64>,
    #[serde(default)]
    pub errmsg: Option<String>,
    #[serde(default)]
    pub total: Option<i64>,
    #[serde(default)]
    pub balance: Option<i64>,
    #[serde(default)]
    pub quota_list: Vec<CustomerAcquisitionQuota>,
    #[serde(default, flatten, skip_serializing_if = "Value::is_null")]
    pub extra: Value,
}

impl CustomerAcquisitionQuotaResponse {
    pub fn validate(&self) -> Result<()> {
        validate_customer_acquisition_response_success(
            "customer-acquisition quota",
            self.errcode,
            self.errmsg.as_deref(),
        )?;
        let total = self.total.ok_or_else(|| {
            WechatError::Config("customer-acquisition quota requires total".to_string())
        })?;
        let balance = self.balance.ok_or_else(|| {
            WechatError::Config("customer-acquisition quota requires balance".to_string())
        })?;
        if total < 0 || balance < 0 || balance > total {
            return Err(WechatError::Config(
                "customer-acquisition quota requires 0 <= balance <= total".to_string(),
            ));
        }
        for quota in &self.quota_list {
            quota.validate()?;
        }
        Ok(())
    }

    pub fn is_exhausted(&self) -> bool {
        self.balance.is_some_and(|balance| balance <= 0)
    }

    pub fn available_balance(&self) -> i64 {
        self.balance.unwrap_or_default().max(0)
    }

    pub fn used(&self) -> Option<i64> {
        Some(self.total?.saturating_sub(self.balance?).max(0))
    }

    pub fn next_expiring_quota(&self) -> Option<&CustomerAcquisitionQuota> {
        self.quota_list
            .iter()
            .filter(|quota| quota.expire_date.is_some())
            .min_by_key(|quota| quota.expire_date)
    }

    pub fn next_active_expiring_quota(
        &self,
        current_timestamp: i64,
    ) -> Option<&CustomerAcquisitionQuota> {
        self.quota_list
            .iter()
            .filter(|quota| {
                quota
                    .expire_date
                    .is_some_and(|expire_date| expire_date > current_timestamp)
                    && quota.balance.is_none_or(|balance| balance > 0)
            })
            .min_by_key(|quota| quota.expire_date)
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CustomerAcquisitionQuota {
    #[serde(default)]
    pub expire_date: Option<i64>,
    #[serde(default)]
    pub balance: Option<i64>,
    #[serde(default, flatten, skip_serializing_if = "Value::is_null")]
    pub extra: Value,
}

impl CustomerAcquisitionQuota {
    pub fn validate(&self) -> Result<()> {
        if self.expire_date.is_some_and(|value| value <= 0) {
            return Err(WechatError::Config(
                "customer-acquisition quota expiry must be positive".to_string(),
            ));
        }
        if self.balance.is_some_and(|value| value < 0) {
            return Err(WechatError::Config(
                "customer-acquisition quota balance cannot be negative".to_string(),
            ));
        }
        Ok(())
    }
}

