fn validate_external_contact_moment_response_success(
    operation: &str,
    errcode: Option<i64>,
    errmsg: Option<&str>,
) -> Result<()> {
    if let Some(code) = errcode.filter(|code| *code != 0) {
        return Err(WechatError::Api {
            code,
            message: errmsg.unwrap_or(operation).to_string(),
        });
    }
    Ok(())
}

fn normalized_external_contact_cursor(cursor: Option<&str>) -> Option<&str> {
    cursor.filter(|cursor| !cursor.trim().is_empty())
}

fn validate_external_contact_moment_response_image(
    image: &ExternalContactMessageImage,
) -> Result<()> {
    let has_media = image
        .media_id
        .as_deref()
        .is_some_and(|value| !value.trim().is_empty());
    let has_url = image
        .pic_url
        .as_deref()
        .is_some_and(|value| !value.trim().is_empty());
    if !has_media && !has_url {
        return Err(WechatError::Config(
            "external-contact moment image requires media_id or pic_url".to_string(),
        ));
    }
    if let Some(url) = image.pic_url.as_deref() {
        validate_external_contact_message_url("moment image pic_url", url)?;
    }
    Ok(())
}

fn validate_external_contact_moment_response_link(link: &ExternalContactMessageLink) -> Result<()> {
    validate_external_contact_message_string("moment link title", link.title.as_deref(), 128)?;
    validate_external_contact_message_string("moment link URL", link.url.as_deref(), 2_048)?;
    validate_external_contact_message_url(
        "moment link URL",
        link.url.as_deref().unwrap_or_default(),
    )?;
    if let Some(pic_url) = link.picurl.as_deref() {
        validate_external_contact_message_url("moment link picture URL", pic_url)?;
    }
    Ok(())
}

fn parse_external_contact_moment_coordinate(
    label: &str,
    value: Option<&str>,
    minimum: f64,
    maximum: f64,
) -> Result<f64> {
    let value = value
        .filter(|value| !value.trim().is_empty())
        .ok_or_else(|| {
            WechatError::Config(format!(
                "external-contact moment location {label} is required"
            ))
        })?;
    let coordinate = value.parse::<f64>().map_err(|_| {
        WechatError::Config(format!(
            "external-contact moment location {label} must be numeric"
        ))
    })?;
    if !coordinate.is_finite() || !(minimum..=maximum).contains(&coordinate) {
        return Err(WechatError::Config(format!(
            "external-contact moment location {label} must be between {minimum} and {maximum}"
        )));
    }
    Ok(coordinate)
}

fn validate_external_contact_moment_interaction_identity(
    kind: &str,
    user_id: Option<&str>,
    external_user_id: Option<&str>,
) -> Result<()> {
    let user_id = user_id.filter(|value| !value.trim().is_empty());
    let external_user_id = external_user_id.filter(|value| !value.trim().is_empty());
    if user_id.is_none() && external_user_id.is_none() {
        return Err(WechatError::Config(format!(
            "external-contact moment {kind} requires userid or external_userid"
        )));
    }
    Ok(())
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ExternalContactUserBehaviorDataRequest {
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub userid: Vec<String>,
    #[serde(default, skip_serializing_if = "Vec::is_empty")]
    pub partyid: Vec<i64>,
    pub start_time: i64,
    pub end_time: i64,
}

impl ExternalContactUserBehaviorDataRequest {
    pub fn validate(&self) -> Result<()> {
        if self.userid.is_empty() && self.partyid.is_empty() {
            return Err(WechatError::Config(
                "external-contact behavior statistics require users or departments".to_string(),
            ));
        }
        if self.userid.len() > 100
            || self.userid.iter().any(|userid| userid.trim().is_empty())
            || has_duplicate_strings(&self.userid)
        {
            return Err(WechatError::Config(
                "external-contact behavior statistics support at most 100 unique non-empty users"
                    .to_string(),
            ));
        }
        if self.partyid.len() > 100
            || self.partyid.iter().any(|partyid| *partyid <= 0)
            || has_duplicate_i64s(&self.partyid)
        {
            return Err(WechatError::Config(
                "external-contact behavior statistics support at most 100 unique positive departments"
                    .to_string(),
            ));
        }
        validate_external_contact_time_range(
            "behavior statistics",
            self.start_time,
            self.end_time,
            30,
        )
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct ExternalContactUserBehaviorDataResponse {
    #[serde(default)]
    pub errcode: Option<i64>,
    #[serde(default)]
    pub errmsg: Option<String>,
    #[serde(default)]
    pub behavior_data: Vec<ExternalContactUserBehaviorData>,
    #[serde(default, flatten, skip_serializing_if = "Value::is_null")]
    pub extra: Value,
}

impl ExternalContactUserBehaviorDataResponse {
    pub fn validate(&self) -> Result<()> {
        validate_work_response_success(
            "external-contact user behavior statistics",
            self.errcode,
            self.errmsg.as_deref(),
        )?;
        if self.behavior_data.len() > 3_100 {
            return Err(WechatError::Config(
                "external-contact behavior response cannot exceed 3100 user-day records"
                    .to_string(),
            ));
        }
        let mut identities = std::collections::HashSet::with_capacity(self.behavior_data.len());
        for behavior in &self.behavior_data {
            behavior.validate()?;
            let identity = (
                behavior.userid.as_deref().unwrap_or_default(),
                behavior.stat_time.unwrap_or_default(),
            );
            if !identities.insert(identity) {
                return Err(WechatError::Config(
                    "external-contact behavior response contains duplicate user-day records"
                        .to_string(),
                ));
            }
        }
        Ok(())
    }

    pub fn find(&self, user_id: &str, stat_time: i64) -> Option<&ExternalContactUserBehaviorData> {
        self.behavior_data.iter().find(|behavior| {
            behavior.userid.as_deref() == Some(user_id) && behavior.stat_time == Some(stat_time)
        })
    }
}

