#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WorkMediaUploadByUrlRequest {
    pub scene: i64,
    #[serde(rename = "type")]
    pub media_type: String,
    pub filename: String,
    pub url: String,
    pub md5: String,
}

impl WorkMediaUploadByUrlRequest {
    pub fn new(
        scene: WorkMediaUploadByUrlSceneKind,
        media_type: WorkMediaUploadByUrlTypeKind,
        filename: impl Into<String>,
        url: impl Into<String>,
        md5: impl Into<String>,
    ) -> Self {
        Self {
            scene: scene.as_code(),
            media_type: media_type.as_code().to_string(),
            filename: filename.into(),
            url: url.into(),
            md5: md5.into(),
        }
    }

    pub fn scene_kind(&self) -> Option<WorkMediaUploadByUrlSceneKind> {
        (self.scene == WorkMediaUploadByUrlSceneKind::ExternalContactGroupWelcome.as_code())
            .then_some(WorkMediaUploadByUrlSceneKind::ExternalContactGroupWelcome)
    }

    pub fn media_type_kind(&self) -> Option<WorkMediaUploadByUrlTypeKind> {
        if self
            .media_type
            .eq_ignore_ascii_case(WorkMediaUploadByUrlTypeKind::Video.as_code())
        {
            Some(WorkMediaUploadByUrlTypeKind::Video)
        } else if self
            .media_type
            .eq_ignore_ascii_case(WorkMediaUploadByUrlTypeKind::File.as_code())
        {
            Some(WorkMediaUploadByUrlTypeKind::File)
        } else {
            None
        }
    }

    pub fn validate(&self) -> Result<()> {
        if self.scene_kind().is_none() {
            return Err(WechatError::Config(
                "work media URL upload scene is unsupported".to_string(),
            ));
        }
        if self.media_type_kind().is_none() {
            return Err(WechatError::Config(
                "work media URL upload type must be video or file".to_string(),
            ));
        }
        validate_work_media_file_name(&self.filename)?;
        let url = url::Url::parse(&self.url).map_err(|error| {
            WechatError::Config(format!("work media URL upload URL is invalid: {error}"))
        })?;
        if !matches!(url.scheme(), "http" | "https") || url.host_str().is_none() {
            return Err(WechatError::Config(
                "work media URL upload URL must be an absolute HTTP(S) URL".to_string(),
            ));
        }
        if self.md5.len() != 32
            || !self
                .md5
                .chars()
                .all(|character| character.is_ascii_hexdigit())
        {
            return Err(WechatError::Config(
                "work media URL upload MD5 must contain 32 hexadecimal characters".to_string(),
            ));
        }
        Ok(())
    }
}

