#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WorkCalendarGetResponse {
    #[serde(default)]
    pub errcode: Option<i64>,
    #[serde(default)]
    pub errmsg: Option<String>,
    #[serde(default)]
    pub calendar_list: Vec<WorkCalendarInfo>,
    #[serde(default, flatten, skip_serializing_if = "Value::is_null")]
    pub extra: Value,
}

impl WorkCalendarGetResponse {
    pub fn validate(&self) -> Result<()> {
        validate_work_response_success(
            "work OA calendar get",
            self.errcode,
            self.errmsg.as_deref(),
        )?;
        if self.calendar_list.len() > 1_000 {
            return Err(WechatError::Config(
                "work OA calendar response cannot contain more than 1000 calendars".to_string(),
            ));
        }
        let mut calendar_ids = std::collections::HashSet::with_capacity(self.calendar_list.len());
        for calendar in &self.calendar_list {
            calendar.validate()?;
            let cal_id = calendar.cal_id.as_deref().unwrap_or_default();
            if !calendar_ids.insert(cal_id) {
                return Err(WechatError::Config(
                    "work OA calendar response cannot contain duplicate calendar ids".to_string(),
                ));
            }
        }
        Ok(())
    }

    pub fn find(&self, cal_id: &str) -> Option<&WorkCalendarInfo> {
        self.calendar_list
            .iter()
            .find(|calendar| calendar.cal_id.as_deref() == Some(cal_id))
    }

    pub fn public_calendar_count(&self) -> usize {
        self.calendar_list
            .iter()
            .filter(|calendar| calendar.is_public_calendar())
            .count()
    }
}
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WorkDialRecordRequest {
    pub start_time: i64,
    pub end_time: i64,
    pub offset: i64,
    pub limit: i64,
}

impl WorkDialRecordRequest {
    pub fn first_page(start_time: i64, end_time: i64, limit: i64) -> Self {
        Self {
            start_time,
            end_time,
            offset: 0,
            limit,
        }
    }

    pub fn recent_30_days(limit: i64) -> Self {
        Self::first_page(0, 0, limit)
    }

    pub fn next_page(&self) -> Option<Self> {
        self.offset.checked_add(self.limit).map(|offset| Self {
            offset,
            ..self.clone()
        })
    }

    pub fn validate(&self) -> Result<()> {
        if self.offset < 0 {
            return Err(WechatError::Config(
                "work dial record offset cannot be negative".to_string(),
            ));
        }
        if !(1..=100).contains(&self.limit) {
            return Err(WechatError::Config(
                "work dial record limit must be between 1 and 100".to_string(),
            ));
        }
        match (self.start_time, self.end_time) {
            (0, 0) => Ok(()),
            (start_time, end_time) if start_time > 0 && end_time >= start_time => {
                if end_time - start_time > 30 * 86_400 {
                    return Err(WechatError::Config(
                        "work dial record time range cannot exceed 30 days".to_string(),
                    ));
                }
                Ok(())
            }
            _ => Err(WechatError::Config(
                "work dial record timestamps must both be zero or a positive ordered range"
                    .to_string(),
            )),
        }
    }
}

