#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum WorkLivingTypeKind {
    General,
    SmallClass,
    LargeClass,
    Training,
    Activity,
    Other,
}

impl WorkLivingTypeKind {
    pub fn from_code(code: i64) -> Self {
        match code {
            0 => Self::General,
            1 => Self::SmallClass,
            2 => Self::LargeClass,
            3 => Self::Training,
            4 => Self::Activity,
            _ => Self::Other,
        }
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum WorkLivingStatusKind {
    Reserved,
    Live,
    Ended,
    Expired,
    Cancelled,
    Other,
}

impl WorkLivingStatusKind {
    pub fn from_code(code: i64) -> Self {
        match code {
            0 => Self::Reserved,
            1 => Self::Live,
            2 => Self::Ended,
            3 => Self::Expired,
            4 => Self::Cancelled,
            _ => Self::Other,
        }
    }

    pub fn is_terminal(self) -> bool {
        matches!(self, Self::Ended | Self::Expired | Self::Cancelled)
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub enum WorkLivingReplayStatusKind {
    Ready,
    Generating,
    Deleted,
    Failed,
    Other,
}

impl WorkLivingReplayStatusKind {
    pub fn from_code(code: i64) -> Self {
        match code {
            0 => Self::Ready,
            1 => Self::Generating,
            2 => Self::Deleted,
            3 => Self::Failed,
            _ => Self::Other,
        }
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct WorkLivingInfo {
    #[serde(default)]
    pub anchor_userid: Option<String>,
    #[serde(default)]
    pub theme: Option<String>,
    #[serde(default)]
    pub living_start: Option<i64>,
    #[serde(default)]
    pub living_duration: Option<i64>,
    #[serde(default)]
    pub description: Option<String>,
    #[serde(default, rename = "type")]
    pub living_type: Option<i64>,
    #[serde(default)]
    pub status: Option<i64>,
    #[serde(default)]
    pub main_department: Option<i64>,
    #[serde(default)]
    pub viewer_num: Option<i64>,
    #[serde(default)]
    pub online_count: Option<i64>,
    #[serde(default)]
    pub open_replay: Option<i64>,
    #[serde(default)]
    pub reserve_living_duration: Option<i64>,
    #[serde(default)]
    pub reserve_start: Option<i64>,
    #[serde(default)]
    pub replay_status: Option<i64>,
    #[serde(default)]
    pub mic_num: Option<i64>,
    #[serde(default)]
    pub push_stream_url: Option<String>,
    #[serde(default)]
    pub subscribe_count: Option<i64>,
    #[serde(default)]
    pub comment_num: Option<i64>,
    #[serde(default, flatten, skip_serializing_if = "Value::is_null")]
    pub extra: Value,
}

impl WorkLivingInfo {
    pub fn validate(&self) -> Result<()> {
        for (label, value) in [
            ("anchor user id", self.anchor_userid.as_deref()),
            ("theme", self.theme.as_deref()),
            ("push stream url", self.push_stream_url.as_deref()),
        ] {
            if let Some(value) = value {
                validate_work_living_identifier(label, value)?;
            }
        }
        for (label, value) in [
            ("start time", self.living_start),
            ("duration", self.living_duration),
            ("reserve duration", self.reserve_living_duration),
            ("reserve start", self.reserve_start),
        ] {
            if value.is_some_and(|value| value <= 0) {
                return Err(WechatError::Config(format!(
                    "work living response {label} must be positive"
                )));
            }
        }
        for (label, value) in [
            ("type", self.living_type),
            ("status", self.status),
            ("replay status", self.replay_status),
            ("main department", self.main_department),
            ("viewer count", self.viewer_num),
            ("online count", self.online_count),
            ("mic count", self.mic_num),
            ("subscriber count", self.subscribe_count),
            ("comment count", self.comment_num),
        ] {
            if value.is_some_and(|value| value < 0) {
                return Err(WechatError::Config(format!(
                    "work living response {label} cannot be negative"
                )));
            }
        }
        validate_work_living_binary_response("open replay", self.open_replay)
    }

    pub fn living_type_kind(&self) -> Option<WorkLivingTypeKind> {
        self.living_type.map(WorkLivingTypeKind::from_code)
    }

    pub fn status_kind(&self) -> Option<WorkLivingStatusKind> {
        self.status.map(WorkLivingStatusKind::from_code)
    }

    pub fn replay_status_kind(&self) -> Option<WorkLivingReplayStatusKind> {
        self.replay_status
            .map(WorkLivingReplayStatusKind::from_code)
    }

    pub fn is_terminal(&self) -> bool {
        self.status_kind()
            .is_some_and(WorkLivingStatusKind::is_terminal)
    }

    pub fn replay_enabled(&self) -> bool {
        self.open_replay == Some(1)
    }
}

#[derive(Debug, Clone, Serialize, Deserialize)]
